import React, { useState } from 'react';
import { aiService } from '../services/aiService';

// Page: Email Drafter
// Supports multiple email types and generates a concise email under 120 words.
const EmailDrafter = () => {
  const [type, setType] = useState('Cold outreach');
  const [form, setForm] = useState({ recipientName: '', company: '', context: '', tone: '' });
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleGenerate = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await aiService.callAI('email', { type, ...form });
      setResult(res.data || res);
    } catch (err) {
      console.error(err);
      alert('AI request failed');
    }
    setLoading(false);
  };

  const copyToClipboard = async () => {
    try {
      await navigator.clipboard.writeText(typeof result === 'string' ? result : JSON.stringify(result));
      alert('Copied to clipboard');
    } catch (err) {
      console.error(err);
      alert('Copy failed');
    }
  };

  return (
    <div>
      <h2>AI Email Drafter</h2>
      <form onSubmit={handleGenerate}>
        <select value={type} onChange={(e) => setType(e.target.value)}>
          <option>Cold outreach</option>
          <option>Follow-up</option>
          <option>Proposal email</option>
          <option>Thank you/project won</option>
        </select>

        <input name="recipientName" placeholder="Recipient name" value={form.recipientName} onChange={handleChange} />
        <input name="company" placeholder="Company" value={form.company} onChange={handleChange} />
        <input name="tone" placeholder="Tone (e.g., professional)" value={form.tone} onChange={handleChange} />
        <textarea name="context" placeholder="Context details" value={form.context} onChange={handleChange} />
        <button type="submit" disabled={loading}>{loading ? 'Generating...' : 'Generate Email'}</button>
      </form>

      {result && (
        <div style={{ marginTop: 20 }}>
          <button onClick={copyToClipboard}>Copy to clipboard</button>
          <pre style={{ whiteSpace: 'pre-wrap' }}>{typeof result === 'string' ? result : JSON.stringify(result, null, 2)}</pre>
        </div>
      )}
    </div>
  );
};

export default EmailDrafter;
